"""
Domain AX Skill-Set Ontology System
Main Entry Point

전체 시스템 통합 실행 및 데모
"""

import argparse
import os
import sys
from pathlib import Path

# 프로젝트 루트를 Python 경로에 추가
project_root = Path(__file__).parent
sys.path.insert(0, str(project_root))


def setup_directories():
    """필요한 디렉토리 생성"""
    directories = [
        'data/ontology',
        'data/raw',
        'data/processed',
        'models/ontology',
        'models/embeddings',
        'outputs/reports',
        'outputs/visualizations'
    ]

    for directory in directories:
        os.makedirs(directory, exist_ok=True)

    print("✓ 디렉토리 구조 생성 완료")


def build_ontology():
    """온톨로지 구축"""
    print("\n" + "="*70)
    print("MODE: 온톨로지 구축")
    print("="*70)

    from src.ontology.ax_ontology_builder import AXOntologyBuilder

    builder = AXOntologyBuilder('data/ontology/ax_ontology.json')
    ontology = builder.build()

    # 저장
    builder.save('models/ontology/ax_competency_ontology.pkl')
    builder.export_to_graphml('outputs/visualizations/ax_ontology.graphml')

    # 예제 조회
    print("\n" + "="*70)
    print("예제 쿼리: AX Lv.1 역량")
    print("="*70)

    lv1_comps = builder.get_competencies_by_level('AX_Lv1')
    print(f"\nAX Lv.1 필요 역량: {len(lv1_comps)}개")

    for i, comp in enumerate(list(lv1_comps)[:5], 1):
        path = builder.get_competency_hierarchy(comp.identifier)
        print(f"\n{i}. {comp.name}")
        print(f"   경로: {' > '.join(path)}")


def run_assessment():
    """역량 평가 실행"""
    print("\n" + "="*70)
    print("MODE: 역량 평가")
    print("="*70)

    from src.assessment.skill_assessor import AXSkillAssessor, AssessmentResult

    # 샘플 데이터
    sample_assessments = [
        {
            'person_id': 'E001',
            'person_name': '홍길동',
            'scores': {
                'C001_A001': 85.0, 'C001_A002': 78.0,
                'C002_A001': 72.0, 'C005_A001': 90.0,
                'C010_A001': 65.0, 'C013_A001': 88.0,
                'C017_A001': 55.0,
            }
        },
        {
            'person_id': 'E002',
            'person_name': '김철수',
            'scores': {
                'C001_A001': 92.0, 'C001_A002': 88.0,
                'C002_A001': 85.0, 'C005_A001': 78.0,
                'C010_A001': 82.0, 'C013_A001': 90.0,
                'C017_A001': 75.0,
            }
        },
        {
            'person_id': 'E003',
            'person_name': '이영희',
            'scores': {
                'C001_A001': 68.0, 'C001_A002': 70.0,
                'C002_A001': 65.0, 'C005_A001': 72.0,
                'C010_A001': 58.0, 'C013_A001': 75.0,
                'C017_A001': 45.0,
            }
        }
    ]

    assessor = AXSkillAssessor(
        ontology_file='models/ontology/ax_competency_ontology.pkl',
        assessment_criteria_file='data/ontology/assessment_criteria.json'
    )

    # 개인별 평가
    results = []
    for person_data in sample_assessments:
        result = assessor.assess_person(
            person_id=person_data['person_id'],
            person_name=person_data['person_name'],
            assessment_data=person_data['scores']
        )
        results.append(result)

    # 팀 평가
    print("\n")
    team_result = assessor.assess_team(results)

    return results, team_result


def run_recommendation():
    """학습 경로 추천 실행"""
    print("\n" + "="*70)
    print("MODE: 학습 경로 추천")
    print("="*70)

    from src.recommender.learning_path import AXLearningPathRecommender

    recommender = AXLearningPathRecommender(
        course_catalog_file='data/courses/course_catalog.json'
    )

    # 시나리오 1: Pre-AX → Lv.2
    print("\n[시나리오 1] 초보자 → 중급자")
    path1 = recommender.recommend_path(
        current_level='Pre-AX',
        target_level='AX_Lv2',
        weak_competencies=['C017', 'C010', 'C013'],
        available_hours_per_week=10
    )

    # 시나리오 2: Quick Wins
    print("\n[시나리오 2] Quick Win 추천")
    quick_wins = recommender.recommend_quick_wins(
        weak_competencies=['C017', 'C018', 'C010'],
        max_hours=20
    )

    # 시나리오 3: 경로 비교
    print("\n[시나리오 3] 학습 경로 비교")
    paths = recommender.compare_paths(
        current_level='AX_Lv1',
        target_level='AX_Lv3'
    )

    return path1, quick_wins, paths


def run_full_demo():
    """전체 시스템 통합 데모"""
    print("\n" + "="*80)
    print("Domain AX Skill-Set Ontology System - 통합 데모")
    print("="*80)

    # 1. 환경 설정
    print("\n[STEP 1] 환경 설정")
    setup_directories()

    # 2. 온톨로지 구축
    print("\n[STEP 2] 온톨로지 구축")
    build_ontology()

    # 3. 역량 평가
    print("\n[STEP 3] 역량 평가")
    assessment_results, team_result = run_assessment()

    # 4. 학습 경로 추천
    print("\n[STEP 4] 학습 경로 추천")

    # 평가 결과 기반 추천
    for result in assessment_results:
        if result.overall_level != 'AX_Lv3':
            print(f"\n{result.person_name}님 맞춤 학습 경로:")

            # 목표 레벨 결정
            level_map = {
                'Pre-AX': 'AX_Lv1',
                'AX_Lv1': 'AX_Lv2',
                'AX_Lv2': 'AX_Lv3'
            }
            target = level_map.get(result.overall_level, 'AX_Lv2')

            # 약점 역량 추출 (간단히 이름에서 ID 추출)
            weak_comp_ids = [w.split('(')[0].strip() for w in result.weaknesses]

            from src.recommender.learning_path import AXLearningPathRecommender
            recommender = AXLearningPathRecommender(
                'data/courses/course_catalog.json'
            )

            path = recommender.recommend_path(
                current_level=result.overall_level,
                target_level=target,
                weak_competencies=weak_comp_ids[:3],
                available_hours_per_week=8
            )

    # 5. 리포트 생성
    print("\n[STEP 5] 리포트 생성")
    generate_report(assessment_results, team_result)

    print("\n" + "="*80)
    print("✓ 전체 데모 완료!")
    print("="*80)
    print("\n생성된 파일:")
    print("  - models/ontology/ax_competency_ontology.pkl")
    print("  - outputs/visualizations/ax_ontology.graphml")
    print("  - outputs/reports/assessment_report.html")


